--
-- Triggers `packed_items`
--
DELIMITER $$
CREATE TRIGGER `after_packed_items_insert` AFTER INSERT ON `packed_items` FOR EACH ROW BEGIN
    DECLARE existing_price DECIMAL(10, 2);

    -- Check if the item already exists in admin_items and get the existing price
    SELECT price INTO existing_price FROM admin_items 
    WHERE item_number = NEW.item_number LIMIT 1;

    IF existing_price IS NOT NULL THEN
        -- If the item exists and has a price, insert or update with the existing price
        VALUES (NEW.item_number, NEW.po_number, NEW.amount, NEW.date_added, NEW.date_packed, existing_price)
        ON DUPLICATE KEY UPDATE
            amount = VALUES(amount),
            date_added = VALUES(date_added),
            date_packed = VALUES(date_packed),
            price = VALUES(price);
    ELSE
        -- If the item does not exist or has no price, insert without the price
        VALUES (NEW.item_number, NEW.po_number, NEW.amount, NEW.date_added, NEW.date_packed)
        ON DUPLICATE KEY UPDATE
            amount = VALUES(amount),
            date_added = VALUES(date_added),
            date_packed = VALUES(date_packed);
    END IF;
END
$$
DELIMITER ;

